def compute_score() -> tuple[str, float]:
    """
    Check ONLY the overall presentation title (the title placeholder on the first slide
    that has one). Passes iff its effective font size is 48pt across all non-empty runs.

    Returns:
      (message, score) where score is 1.0 on success, else 0.0
    """
    from pptx import Presentation
    from pptx.enum.shapes import PP_PLACEHOLDER

    TARGET_PT = 48.0
    TOL = 0.5  # tolerate tiny rounding diffs

    def approx_eq(x, y, tol=TOL):
        try:
            return abs(float(x) - float(y)) <= tol
        except Exception:
            return False

    def get_title_shape(slide):
        # Prefer the library helper
        t = getattr(slide.shapes, "title", None)
        if t is not None:
            return t
        # Fallback: find a placeholder of type TITLE or CENTER_TITLE
        for sh in slide.shapes:
            try:
                if getattr(sh, "is_placeholder", False) and sh.is_placeholder:
                    ph_type = sh.placeholder_format.type
                    if ph_type in (PP_PLACEHOLDER.TITLE, PP_PLACEHOLDER.CENTER_TITLE):
                        return sh
            except Exception:
                continue
        return None

    def gather_title_sizes_pt(title_shape):
        """
        Collect effective point sizes for non-empty runs in the title.
        Prefer run.font.size; if None, fall back to paragraph.font.size.
        Returns a list of floats; may be empty if all sizes are inherited from master/layout.
        """
        sizes = []
        tf = getattr(title_shape, "text_frame", None)
        if not tf:
            return sizes

        for para in tf.paragraphs:
            # paragraph-level fallback
            psize = getattr(getattr(para, "font", None), "size", None)
            p_pt = float(psize.pt) if psize is not None else None

            for run in para.runs:
                txt = (run.text or "").strip()
                if not txt:
                    continue
                rsize = getattr(getattr(run, "font", None), "size", None)
                if rsize is not None:
                    try:
                        sizes.append(float(rsize.pt))
                        continue
                    except Exception:
                        pass
                if p_pt is not None:
                    sizes.append(p_pt)
        return sizes

    # ---- main logic ----
    try:
        pres = Presentation(modified_ppt_path)
    except Exception as e:
        return f"Failed to open presentation: {e}", 0.0

    title_shape = None
    slide_no = None
    for idx, slide in enumerate(pres.slides, start=1):
        t = get_title_shape(slide)
        if t is not None:
            title_shape = t
            slide_no = idx
            break

    if title_shape is None:
        return "No overall title found (no slide has a title placeholder).", 0.0

    sizes = gather_title_sizes_pt(title_shape)
    if not sizes:
        # Nothing explicitly set at run/paragraph level
        return (f"Overall title on slide {slide_no} has no explicit font size "
                f"(inherited from layout/master) — cannot verify 48pt.", 0.0)

    # Normalize and dedupe with a little rounding to reduce noise
    uniq = sorted({round(s, 1) for s in sizes})

    # If multiple sizes used in the title, require that all are ~48pt
    if all(approx_eq(s, TARGET_PT) for s in uniq):
        return f"Overall title on slide {slide_no} is 48pt.", 1.0

    # Otherwise, fail and report what we saw
    if len(uniq) == 1:
        return f"Overall title on slide {slide_no} is {uniq[0]}pt, not 48pt.", 0.0
    else:
        return (f"Overall title on slide {slide_no} has mixed sizes {uniq}pt (expected 48pt).",
                0.0)

def compute_score() -> tuple[str, float]:
    # Check for slide additions/removals
    if ppt_diff.added_slides:
        return f"Unexpected slides were added: {len(ppt_diff.added_slides)} slides", 0.0

    if ppt_diff.removed_slides:
        return f"Unexpected slides were removed: {len(ppt_diff.removed_slides)} slides", 0.0

    # Check for slide modifications (should be minimal - only title font changes)
    if ppt_diff.modified_slides:
        # This is expected since we're changing title font, but let's verify it's reasonable
        modified_count = len(ppt_diff.modified_slides)
        if modified_count > 10:  # Reasonable threshold
            return f"Too many slides were modified: {modified_count} slides", 0.5
        else:
            return f"Acceptable number of slide modifications: {modified_count} slides", 1.0

    return "No unexpected slide changes detected", 1.0

def compute_score() -> tuple[str, float]:
    issues = []

    if ppt_diff.added_animations:
        issues.append(f"{len(ppt_diff.added_animations)} animations were added")

    if ppt_diff.removed_animations:
        issues.append(f"{len(ppt_diff.removed_animations)} animations were removed")

    if ppt_diff.modified_animations:
        issues.append(f"{len(ppt_diff.modified_animations)} animations were modified")

    if ppt_diff.added_transitions:
        issues.append(f"{len(ppt_diff.added_transitions)} transitions were added")

    if ppt_diff.removed_transitions:
        issues.append(f"{len(ppt_diff.removed_transitions)} transitions were removed")

    if ppt_diff.modified_transitions:
        issues.append(f"{len(ppt_diff.modified_transitions)} transitions were modified")

    if issues:
        return f"Unexpected animation/transition changes: {'; '.join(issues)}", 0.0

    return "No unexpected animation or transition changes", 1.0
